define i1 @trunc_unsigned_nuw_zext(i32 %x, i8 %y) {
  %xt = trunc nuw i32 %x to i16
  %ye = zext i8 %y to i16
  %c = icmp ult i16 %xt, %ye
  ret i1 %c
}

log.expect_optimized_program:
define i1 @trunc_unsigned_nuw_zext(i32 %x, i8 %y) {
  %1 = zext i8 %y to i32
  %c = icmp ult i32 %x, %1
  ret i1 %c
}

